1	import { NextRequest } from "next/server";
2	import { jwtVerify } from "jose";
3	
4	export interface AuthUser {
5	  userId: string;
6	  role: "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";
7	  deptId: string;
8	}
9	
10	export class AuthError extends Error {
11	  constructor(
12	    message: string,
13	    public statusCode: number = 401,
14	  ) {
15	    super(message);
16	    this.name = "AuthError";
17	  }
18	}
19	
20	const AUTH_SECRET =
21	  process.env.AUTH_SECRET ?? "it-asset-dev-secret-change-in-production";
22	const secretKey = new TextEncoder().encode(AUTH_SECRET);
23	
24	const demoTokenPrefix = "demo-token-";
25	
26	const demoUserMap: Record<string, AuthUser> = {
27	  EMPLOYEE:  { userId: "demo-emp",  role: "EMPLOYEE",  deptId: "dept-tech" },
28	  MANAGER:   { userId: "demo-mgr",  role: "MANAGER",   deptId: "dept-tech" },
29	  IT_ADMIN:  { userId: "demo-it",   role: "IT_ADMIN",  deptId: "dept-it" },
30	  EXECUTIVE: { userId: "demo-exec", role: "EXECUTIVE", deptId: "dept-mgmt" },
31	};
32	
33	export async function verifyAuth(
34	  request: NextRequest,
35	): Promise<AuthUser> {
36	  const authHeader = request.headers.get("authorization");
37	
38	  if (!authHeader?.startsWith("Bearer ")) {
39	    throw new AuthError("Missing or invalid authorization header");
40	  }
41	
42	  const token = authHeader.slice(7);
43	
44	  // Demo token: bypass JWT verification
45	  if (token.startsWith(demoTokenPrefix)) {
46	    const tokenBody = token.slice(demoTokenPrefix.length);
47	    const lastDash = tokenBody.lastIndexOf("-");
48	    if (lastDash === -1) {
49	      throw new AuthError("Invalid demo token");
50	    }
51	    const role = tokenBody.slice(0, lastDash);
52	    const authUser = demoUserMap[role];
53	    if (!authUser) {
54	      throw new AuthError("Invalid demo token");
55	    }
56	    return authUser;
57	  }
58	
59	  try {
60	    const { payload } = await jwtVerify(token, secretKey);
61	    return {
62	      userId: payload.sub as string,
63	      role: payload.role as AuthUser["role"],
64	      deptId: payload.deptId as string,
65	    };
66	  } catch {
67	    throw new AuthError("Invalid or expired token");
68	  }
69	}
70	
71	export function requireOneOf(
72	  user: AuthUser,
73	  ...roles: AuthUser["role"][]
74	): void {
75	  if (!roles.includes(user.role)) {
76	    throw new AuthError("Insufficient permissions", 403);
77	  }
78	}
