3	import React, {
4	  createContext,
5	  useCallback,
6	  useContext,
7	  useEffect,
8	  useMemo,
9	  useState,
10	} from "react";
11	import { apiFetch, setToken, clearToken, getToken } from "./api-client";
12	
13	export type UserRole = "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";
14	
15	export interface User {
16	  id: string;
17	  name: string;
18	  email: string;
19	  role: UserRole;
20	  avatar?: string;
21	  department: string;
22	  departmentId: string;
23	}
24	
25	interface LoginResponse {
26	  token: string;
27	  user: User;
28	}
29	
30	interface SessionResponse {
31	  user: User;
32	}
33	
34	interface AuthContextType {
35	  user: User | null;
36	  token: string | null;
37	  loading: boolean;
38	  login: (email: string, password: string) => Promise<void>;
39	  loginAsDemo: (role: UserRole) => void;
40	  logout: () => void;
41	  setRole: (role: UserRole) => void;
42	  unreadNotifications: number;
43	  setUnreadNotifications: (n: number) => void;
44	}
45	
46	const AuthContext = createContext<AuthContextType | null>(null);
47	
48	const demoUsers: Record<UserRole, User> = {
49	  EMPLOYEE:  { id: "demo-emp",  name: "张三", email: "zhangsan@example.com",   role: "EMPLOYEE",  department: "技术部", departmentId: "dept-tech" },
50	  MANAGER:   { id: "demo-mgr",  name: "李四", email: "lisi@example.com",       role: "MANAGER",   department: "技术部", departmentId: "dept-tech" },
51	  IT_ADMIN:  { id: "demo-it",   name: "王五", email: "wangwu@example.com",     role: "IT_ADMIN",  department: "IT 部", departmentId: "dept-it" },
52	  EXECUTIVE: { id: "demo-exec", name: "赵六", email: "zhaoliu@example.com",    role: "EXECUTIVE", department: "管理层", departmentId: "dept-mgmt" },
53	};
54	
55	export function AuthProvider({ children }: { children: React.ReactNode }) {
56	  const [user, setUser] = useState<User | null>(null);
57	  const [token, setTokenState] = useState<string | null>(null);
58	  const [loading, setLoading] = useState(true);
59	  const [unreadNotifications, setUnreadNotifications] = useState(0);
60	
61	  // Restore session on mount
62	  useEffect(() => {
63	    const storedToken = getToken();
64	    if (storedToken) {
65	      setTokenState(storedToken);
66	      apiFetch<SessionResponse>("/api/auth/session")
67	        .then((data) => {
68	          setUser(data.user);
69	        })
70	        .catch(() => {
71	          // Session invalid, clear token
72	          clearToken();
73	          setTokenState(null);
74	          setUser(null);
75	        })
76	        .finally(() => {
77	          setLoading(false);
78	        });
79	    } else {
80	      setLoading(false);
81	    }
82	  }, []);
83	
84	  const login = useCallback(async (email: string, password: string) => {
85	    const data = await apiFetch<LoginResponse>("/api/auth/login", {
86	      method: "POST",
87	      body: JSON.stringify({ email, password }),
88	    });
89	    setToken(data.token);
90	    setTokenState(data.token);
91	    setUser(data.user);
92	  }, []);
93	
94	  const loginAsDemo = useCallback((role: UserRole) => {
95	    const demoUser = demoUsers[role];
96	    const fakeToken = "demo-token-" + role + "-" + Date.now();
97	    setToken(fakeToken);
98	    setTokenState(fakeToken);
99	    setUser(demoUser);
100	  }, []);
101	
102	  const logout = useCallback(() => {
103	    // Fire and forget the logout request
104	    apiFetch("/api/auth/logout", { method: "POST" }).catch(() => {
105	      // ignore errors
106	    });
107	    clearToken();
108	    setTokenState(null);
109	    setUser(null);
110	  }, []);
111	
112	  const setRole = useCallback(
113	    (role: UserRole) => {
114	      setUser((prev) => (prev ? { ...prev, role } : prev));
115	    },
116	    [],
117	  );
118	
119	  const value = useMemo<AuthContextType>(
120	    () => ({
121	      user,
122	      token,
123	      loading,
124	      login,
125	      loginAsDemo,
126	      logout,
127	      setRole,
128	      unreadNotifications,
129	      setUnreadNotifications,
130	    }),
131	    [user, token, loading, login, loginAsDemo, logout, setRole, unreadNotifications],
132	  );
133	
134	  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
135	}
136	
137	export function useAuth(): AuthContextType {
138	  const ctx = useContext(AuthContext);
139	  if (!ctx) {
140	    throw new Error("useAuth must be used within an AuthProvider");
141	  }
142	  return ctx;
143	}
